// ====== CONFIG ======
const ENGINE_VERSION = "engine-1";
const ASSETS_VERSION = "assets-2026-02";

const TEMPLATES_DIR = "/mnt/razresheno/templates";
const OUT_CLOUD_DIR = "/mnt/razresheno/renders/previews";      // куда копируем в Nextcloud
const OUT_LOCAL_DIR = "/opt/razresheno/renders/previews";      // куда реально рендерим
const TMP_DIR = "/opt/razresheno/renders/tmp";

const POINTS_COUNT = 8;

// 1600x2400: нижняя четверть y>=1800, поля >=100
// ВАЖНО: bg_files убрали — фон выбираем из реальных файлов в папке bg*.png
const TEMPLATE_REGISTRY = {
  t01: {
    name: "Classic A",
    seal_presets: [
      { x: 920, y: 1820, rotation: -8,  scale: 0.82, opacity: 0.78 },
      { x: 980, y: 1880, rotation: -12, scale: 0.82, opacity: 0.80 },
      { x: 1040,y: 1860, rotation: -6,  scale: 0.82, opacity: 0.76 },
    ],
    stamp_presets: [
      { x: 220, y: 1900, rotation: 10, scale: 0.90, opacity: 0.90 },
      { x: 260, y: 1980, rotation: 8,  scale: 0.90, opacity: 0.88 },
      { x: 320, y: 1940, rotation: 14, scale: 0.90, opacity: 0.92 },
    ],
  },
  t02: {
    name: "Minimal B",
    seal_presets: [
      { x: 980, y: 1840, rotation: -10, scale: 0.82, opacity: 0.78 },
      { x: 1040,y: 1900, rotation: -15, scale: 0.82, opacity: 0.80 },
    ],
    stamp_presets: [
      { x: 240, y: 1920, rotation: 10, scale: 0.90, opacity: 0.90 },
      { x: 300, y: 2000, rotation: 6,  scale: 0.90, opacity: 0.88 },
    ],
  },
  t03: {
    name: "Bold C",
    seal_presets: [
      { x: 1000,y: 1860, rotation: -5, scale: 0.82, opacity: 0.76 },
      { x: 920, y: 1820, rotation: -9, scale: 0.82, opacity: 0.80 },
    ],
    stamp_presets: [
      { x: 260, y: 1960, rotation: 16, scale: 0.90, opacity: 0.92 },
      { x: 320, y: 2020, rotation: 12, scale: 0.90, opacity: 0.90 },
    ],
  },
};

// ====== HELPERS ======
function simpleHash(str) {
  let h = 0;
  for (let i = 0; i < str.length; i++) h = (h * 31 + str.charCodeAt(i)) >>> 0;
  return h;
}

function pickDeterministic(arr, seedStr) {
  if (!arr || !arr.length) throw new Error("pickDeterministic: empty array");
  const h = simpleHash(seedStr);
  return arr[h % arr.length];
}

function pickTemplateId(requestId, idx) {
  const keys = Object.keys(TEMPLATE_REGISTRY);
  return pickDeterministic(keys, `${requestId}:tpl:${idx}`);
}

function shuffleDeterministic(arr, seedStr) {
  const a = [...arr];
  let h = simpleHash(seedStr);
  for (let i = a.length - 1; i > 0; i--) {
    const j = h % (i + 1);
    [a[i], a[j]] = [a[j], a[i]];
    h = (h * 1103515245 + 12345) >>> 0;
  }
  return a;
}

function sampleDeterministic(arr, seedStr, n) {
  if (!arr || !arr.length) return [];
  const shuffled = shuffleDeterministic(arr, seedStr);
  return shuffled.slice(0, Math.min(n, shuffled.length));
}

function uniqueNonEmpty(arr) {
  const seen = new Set();
  const out = [];
  for (const item of (arr || [])) {
    const s = String(item ?? "").trim();
    if (!s) continue;
    if (seen.has(s)) continue;
    seen.add(s);
    out.push(s);
  }
  return out;
}

function buildPointsPool(phrasesDb, category) {
  const universal = Array.isArray(phrasesDb?.points?.universal) ? phrasesDb.points.universal : [];
  const categoryPool = (phrasesDb?.points && Array.isArray(phrasesDb.points[category]))
    ? phrasesDb.points[category]
    : [];

  // Если категория universal — не дублируем universal дважды
  if (category === "universal") {
    return uniqueNonEmpty(universal);
  }

  // Сначала категорийные фразы, потом добивка universal
  return uniqueNonEmpty([...categoryPool, ...universal]);
}

// ====== INPUTS ======
const session = $node["FN_PARSE_SESSION"]?.json?.session ?? $json.session ?? {};
const reqNode = $node["PG_GET_REQUEST"]?.json ?? {};
const req = reqNode.request ?? reqNode;
const phrasesDb = $node["FN_PARSE_PHRASES"]?.json?.phrasesDb ?? $json.phrasesDb ?? {};

// bgFiles приходят из новых нод
const bgFiles = $node["FN_PARSE_BGS"]?.json?.bgFiles ?? [];
if (!bgFiles.length) throw new Error("bgFiles empty (FN_PARSE_BGS)");

const requestId = String(req.id ?? session.active_request_id ?? "");
if (!requestId) throw new Error("No requestId");

const tgUserId = String(session.tg_user_id ?? "");
if (!tgUserId) throw new Error("No tg_user_id in session");

const recipient = String(req.recipient_name ?? session.recipient_name ?? "Получатель");

const initiatorName = String(
  session.tg_first_name ??
  session.first_name ??
  "Инициатор"
).trim();

const callback = String(
  $json.callback_data ??
  $json.data ??
  $json.callback?.data ??
  $json.body?.callback_query?.data ??
  ""
);

// idx: GEN_FIRST => 1, GEN_NEXT => last+1 (до 3)
let idx;
if (callback === "GEN_FIRST") {
  idx = 1;
} else {
  const last = Number(session.last_variant_idx ?? 0);
  idx = Math.min(last + 1, 3);
  if (idx < 1) idx = 1;
}

// Детерминированный seed на вариант: один requestId + idx = один вариант
const seed = `${requestId}:v:${idx}`;

// ====== TEMPLATE + LAYOUT ======
const template_id = pickTemplateId(requestId, idx);
const tpl = TEMPLATE_REGISTRY[template_id];

const sealPreset = pickDeterministic(tpl.seal_presets, `${seed}:seal`);
const stampPreset = pickDeterministic(tpl.stamp_presets, `${seed}:stamp`);

// ФОН: выбираем из ВСЕХ bg*.png, детерминированно для конкретного варианта
const bgFile = pickDeterministic(bgFiles, `${seed}:bg`);

// ====== CONTENT FROM phrases.json ======
const cat = String(session.category ?? "universal");

const intros = Array.isArray(phrasesDb.intros) && phrasesDb.intros.length
  ? phrasesDb.intros
  : ["Настоящим разрешается:"];

// интро тоже детерминировано на вариант
const intro = pickDeterministic(intros, `${seed}:intro`);

// пул пунктов:
// 1) берём категорию
// 2) если не хватает — добиваем universal
// 3) убираем дубли
const pointsPool = buildPointsPool(phrasesDb, cat);

if (!pointsPool.length) {
  throw new Error(`points pool empty for category=${cat}`);
}

// пункты: ДОЛЖНО БЫТЬ 8, как в тесте
const points = sampleDeterministic(pointsPool, `${seed}:points`, POINTS_COUNT);

// ====== VARIANT ======
const variant = {
  idx,
  recipient_name: recipient,
  initiator_name: initiatorName,
  template_id,
  bg: bgFile,
  layout: {
    seal: {
      x: sealPreset.x,
      y: sealPreset.y,
      rot: sealPreset.rotation,
      scale: sealPreset.scale,
      opacity: sealPreset.opacity,
      color: "season_pink"
    },
    stamp: {
      x: stampPreset.x,
      y: stampPreset.y,
      rot: stampPreset.rotation,
      scale: stampPreset.scale,
      opacity: stampPreset.opacity
    }
  },
  content: { intro, points },
  meta: {
    engine_version: ENGINE_VERSION,
    assets_version: ASSETS_VERSION,
    created_at: Math.floor(Date.now() / 1000),
  },
};

const variant_json = JSON.stringify(variant);
const docNo = `0803-${(simpleHash(seed) % 900) + 100}`;

// ====== PATHS ======
const inPath = `${TMP_DIR}/req${requestId}_v${idx}.json`;
const outPathLocal = `${OUT_LOCAL_DIR}/req${requestId}_v${idx}.png`;
const outPathCloud = `${OUT_CLOUD_DIR}/req${requestId}_v${idx}.png`;

// ====== RENDER JSON ======
const renderJson = {
  mode: "preview",
  templates_dir: TEMPLATES_DIR,
  bg: bgFile,

  doc_no: docNo,
  recipient_name: recipient,
  initiator_name: initiatorName,

  header_small: "Специальный выпуск к 8 марта\nРегламентирующая инстанция «РАЗРЕШЕНО»",
  title: "РАЗРЕШЕНО",
  subtitle: `ОФИЦИАЛЬНЫЙ ДОКУМЕНТ № ${docNo}`,
  intro,
  points,

  footer_lines: ["Вступает в силу немедленно.", "Обжалованию не подлежит."],
  watermark_lines: ["Предварительная версия.", "Не заверено."],
  source_line: "Источник оформления: razresheno",

  qr_url: "https://t.me/razresheno_buro_bot?start=docqr",
  text_block_y: 760,

  layout: variant.layout,
  output_path: outPathLocal
};

return [{
  json: {
    ...$json,

    request_id: requestId,
    tg_user_id: tgUserId,

    idx,
    variant,
    variant_json,
    variantKey: `razresheno:req:${requestId}:v:${idx}`,

    inPath,
    outPathLocal,
    outPathCloud,
    renderJson,

    session_patch: {
      current_variant_idx: String(idx),
      last_variant_idx: String(idx),
      awaiting: "none"
    }
  }
}];

// Берём текущую session
const session = $node["FN_PARSE_SESSION"]?.json?.session ?? $json.session ?? {};
const tgUserId = String(session.tg_user_id ?? $json.tg_user_id ?? "");
if (!tgUserId) throw new Error("No tg_user_id");

// idx после генерации: сначала $json.idx, потом variant.idx
const idx =
  Number($json.idx ?? $json.variant?.idx ?? 0);

if (!idx) throw new Error("No idx after generation");

// Патчим session
const patched = {
  ...session,
  current_variant_idx: String(idx),
  last_variant_idx: String(idx),
  awaiting: "none",
};

// (опционально) оставим active_request_id как есть, не трогаем
// patched.active_request_id = session.active_request_id;

return [{
  json: {
    tg_user_id: tgUserId,
    session: patched
  }
}];

