const raw = $json.session ?? $json.redis?.session ?? $json.redis?.data ?? $json.data ?? null;

let sess = {};
try {
  let parsed = raw;
  if (typeof parsed === "string") parsed = JSON.parse(parsed);
  if (typeof parsed === "string") parsed = JSON.parse(parsed); // на случай двойной сериализации
  if (parsed && typeof parsed === "object" && !Array.isArray(parsed)) sess = parsed;
} catch (e) {
  sess = {};
}

sess.active_request_id = sess.active_request_id ?? null;
sess.awaiting = sess.awaiting ?? "none";
sess.current_variant_idx = String(sess.current_variant_idx ?? "0");
sess.last_variant_idx = String(sess.last_variant_idx ?? "0");
sess.recipient_name = sess.recipient_name ?? null;
sess.last_inline_message_id = sess.last_inline_message_id ?? null;

return [{ json: { ...$json, session: sess } }];

// достаём requestId из разных мест
const rid =
  $json.active_request_id ??
  $json.session?.active_request_id ??
  $json.request_id ??
  null;

if (!rid) throw new Error("GEN: active_request_id is missing");

// возвращаем КОРРЕКТНЫЙ item-формат
return [{
  json: {
    ...$json,
    active_request_id: String(rid),
  }
}];

