  const remaining = 3 - idx;
  let availability = "";
  if (remaining === 2) {
    availability = "Осталось 2 варианта в рамках текущего обращения.\n\n";
  } else if (remaining === 1) {
    availability = "Остался 1 вариант в рамках текущего обращения.\n\n";
  } else {
    availability = "Подготовка вариантов в рамках текущего обращения завершена.\n\n";
  }

  return {
    chat_id: $node["When Executed by Another Workflow"].json.chat_id,
    text:
      header +
      availability +
      "Вступает в силу немедленно.\nОбжалованию не подлежит.",
    reply_markup: idx < 3
      ? {
          inline_keyboard: [
            [{ text: "Подготовить другой вариант", callback_data: "GEN_NEXT" }],
            [{ text: "Перейти к заверению", callback_data: "GO_SEAL" }]
          ]
        }
      : {
          inline_keyboard: [
               [{ text: "Вариант 1", callback_data: "SEAL_PICK:1" }],
              [{ text: "Вариант 2", callback_data: "SEAL_PICK:2" }],
              [{ text: "Вариант 3", callback_data: "SEAL_PICK:3" }]
          ]
        }
  };
})()
}}

